#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

/*
 * HAL-Level Virtualization (Hypervisor) Demonstration
 * Level 2 in the virtualization hierarchy
 * 
 * This demonstrates how hypervisors create virtual machines
 * with virtualized hardware (CPU, memory, I/O)
 */

#define VM_MAX_COUNT 4
#define VM_MEMORY_DEFAULT (1024 * 1024 * 1024)  // 1GB default

// Virtual Machine Control Structure (VMCS) - simplified
typedef struct {
    int vm_id;
    char state[16];              // running, stopped, paused
    uint64_t vcpu_count;
    uint64_t allocated_memory;   // Virtual memory size
    uint64_t vcpu_state[16];     // Virtual CPU registers
    void *hypervisor_context;    // Pointer to hypervisor data
} VirtualMachine;

// Hypervisor structure
typedef struct {
    char name[64];
    int vm_count;
    VirtualMachine *vms[VM_MAX_COUNT];
    uint64_t total_host_memory;
    uint64_t available_memory;
} Hypervisor;

// Initialize hypervisor
Hypervisor* hypervisor_init(const char *name, uint64_t total_memory) {
    Hypervisor *hyper = (Hypervisor *)malloc(sizeof(Hypervisor));
    if (!hyper) return NULL;

    strncpy(hyper->name, name, 63);
    hyper->name[63] = '\0';
    hyper->vm_count = 0;
    hyper->total_host_memory = total_memory;
    hyper->available_memory = total_memory;

    printf("[Hypervisor] %s initialized with %lu MB memory\n", 
           name, total_memory / (1024 * 1024));

    return hyper;
}

// Create a virtual machine (Full Virtualization)
VirtualMachine* create_vm(Hypervisor *hyper, int vcpus, uint64_t memory) {
    if (hyper->vm_count >= VM_MAX_COUNT) {
        printf("[Error] Maximum VM count reached\n");
        return NULL;
    }

    if (memory > hyper->available_memory) {
        printf("[Error] Insufficient memory\n");
        return NULL;
    }

    VirtualMachine *vm = (VirtualMachine *)malloc(sizeof(VirtualMachine));
    if (!vm) return NULL;

    vm->vm_id = hyper->vm_count;
    strcpy(vm->state, "created");
    vm->vcpu_count = vcpus;
    vm->allocated_memory = memory;
    memset(vm->vcpu_state, 0, sizeof(vm->vcpu_state));

    hyper->available_memory -= memory;
    hyper->vms[hyper->vm_count] = vm;
    hyper->vm_count++;

    printf("[VM %d] Created with %lu MB memory, %lu vCPUs\n",
           vm->vm_id, memory / (1024 * 1024), vcpus);

    return vm;
}

// Hypervisor intercepts hardware access
void vm_hardware_intercept(VirtualMachine *vm, int access_type) {
    // Hypervisor intercepts and emulates hardware access
    // This is the key difference from containers

    switch(access_type) {
        case 0:  // Memory access
            printf("[VM %d] Memory access intercepted by hypervisor\n", vm->vm_id);
            printf("         -> Translating virtual address to physical\n");
            break;
        case 1:  // I/O port access
            printf("[VM %d] I/O access intercepted by hypervisor\n", vm->vm_id);
            printf("         -> Emulating or pass-through to device\n");
            break;
        case 2:  // CPU instruction (privileged)
            printf("[VM %d] Privileged instruction trapped\n", vm->vm_id);
            printf("         -> Handling via hypervisor call\n");
            break;
    }
}

// Simulate VM execution
void run_vm(VirtualMachine *vm) {
    strcpy(vm->state, "running");
    printf("[VM %d] Started execution - state: %s\n", vm->vm_id, vm->state);

    // Simulate some hardware accesses that hypervisor intercepts
    vm_hardware_intercept(vm, 0);  // Memory
    vm_hardware_intercept(vm, 1); // I/O
    vm_hardware_intercept(vm, 2); // CPU
}

int main() {
    printf("========================================\n");
    printf("HAL-Level Virtualization Demo\n");
    printf("========================================\n\n");

    // Initialize hypervisor with 8GB host memory
    Hypervisor *hyper = hypervisor_init("KVM-Style Hypervisor", 
                                         8UL * 1024 * 1024 * 1024);

    // Create multiple VMs (each with own virtual hardware)
    printf("\n--- Creating Virtual Machines ---\n");
    create_vm(hyper, 2, 1024UL * 1024 * 1024);  // 2 vCPUs, 1GB
    create_vm(hyper, 4, 2048UL * 1024 * 1024);  // 4 vCPUs, 2GB
    create_vm(hyper, 1, 512UL * 1024 * 1024);   // 1 vCPU, 512MB

    printf("\n--- Running Virtual Machines ---\n");
    // Run each VM
    for (int i = 0; i < hyper->vm_count; i++) {
        run_vm(hyper->vms[i]);
    }

    printf("\n--- Hypervisor Status ---\n");
    printf("Total VMs: %d\n", hyper->vm_count);
    printf("Available memory: %lu MB\n", 
           hyper->available_memory / (1024 * 1024));

    printf("\n========================================\n");
    printf("Key HAL-Level Virtualization Concepts:\n");
    printf("- Each VM has virtual hardware (vCPU, vRAM)\n");
    printf("- Hypervisor intercepts all hardware access\n");
    printf("- Full virtualization: unmodified guest OS\n");
    printf("- Uses binary translation or hardware assist\n");
    printf("- VMs have separate OS kernels\n");
    printf("========================================\n");

    return 0;
}
